import type { IField } from '../types/field.types';

export function createField<T>(value: T, opts?: { displayOnly?: boolean }): IField<T> {
  return {
    value,
    initialValue: value,
    error: undefined,
    isChanged: false,
  };
}

export function setFieldValue<T>(field: IField<T>, value: T, displayOnly = false): IField<T> {
  return {
    ...field,
    value,
    isChanged: displayOnly ? false : value !== field.initialValue,
    error: undefined,
  };
}

export function setFieldError<T>(field: IField<T>, error?: string): IField<T> {
  return { ...field, error };
}

export function newLineId(): string {
  return `line-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}
